import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // Quote: empty and single items
  it.todo("empty item list yields premium of 5 G (processing fee only)");
  it.todo("single sword (no modifiers, first-time customer) yields 115 G (100 base + 10 first + 5 fee)");
  it.todo("single amulet yields 71 G (60 base + 6 first + 5 fee, rounded up)");
  it.todo("single staff yields 93 G (80 base + 8 first + 5 fee)");
  it.todo("single potion yields 49 G (40 base + 4 first + 5 fee)");

  // Components
  it.todo("single rune yields 33 G (25 base + 2.5 first rounded up + 5 fee = 32.5 -> 33)");
  it.todo("3 alike runes form a block: 60 G base premium");
  it.todo("4 runes do not form a block: 100 G base premium");
  it.todo("2 runes + 1 moonstone: no block (different types), 75 G base premium");
  it.todo("3 runes + 3 moonstones: two separate blocks, 120 G base premium");

  // Item-specific modifiers
  it.todo("cursed sword adds 50% surcharge on item base premium (newcomer cursed sword: 165 G)");
  it.todo("high enchantment (>=5) sword adds 30% surcharge");
  it.todo("enchantment 4 sword does not add high-enchantment surcharge");
  it.todo("cursed AND high-enchantment sword stacks both surcharges");

  // Policy-wide modifiers
  it.todo("loyalty discount (>=2 years) applies 20% off the policy base premium");
  it.todo("exactly 2 years customer receives loyalty discount");
  it.todo("follow-up contract (second quote in scenario) applies 15% discount");
  it.todo("first-insurance surcharge applies per item even for follow-up contracts");

  // Multi-item modifier scope
  it.todo("cursed surcharge applies only to cursed item, not whole policy");

  // Rounding
  it.todo("premium rounds up in MHPCO's favor");

  // Integration examples
  it.todo("newcomer with cursed sword: 165 G");
  it.todo("long-standing customer's second contract with cursed enchantment-7 sword: 160 G");

  // Claim: basic payouts
  it.todo("regular sword damage 500 G yields payout 400 G (minus 100 deductible)");
  it.todo("damage to rune (250 G value) of 200 G yields payout 100 G");
  it.todo("high-enchantment (>=8) item: 50% reimbursement then deductible");
  it.todo("dragon material item: full reimbursement then deductible");
  it.todo("dragon material with enchantment 9: 50% wins, then deductible");

  // Claim: cap and deductible
  it.todo("payout capped at 2x insurance sum across multiple claims");
  it.todo("deductible applies per damaged item entry");
  it.todo("two-sword policy: insurance sum 2000, cap 4000");
  it.todo("payout rounds down in MHPCO's favor");

  // Errors
  it.todo("quote with unknown item type causes non-zero exit");
  it.todo("claim against item not in policy causes non-zero exit");
  it.todo("claim with negative damage amount causes non-zero exit");
  it.todo("more damages of a type than insured items causes non-zero exit");

  // CLI
  it.todo("CLI reads JSON from stdin and writes results JSON to stdout");
});

