const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
};

type Item = { type: string };
type Step = { op: string; items: Item[] };
type Input = { steps: Step[] };

const itemPremium = (item: Item): number => {
  const base = BASE_PREMIUMS[item.type] ?? 0;
  return base + base * FIRST_INSURANCE_SURCHARGE_RATE;
};

const quotePremium = (step: Step): number => {
  const itemsTotal = step.items.reduce((sum, item) => sum + itemPremium(item), 0);
  return Math.ceil(itemsTotal) + PROCESSING_FEE;
};

export const runScenario = (input: unknown): unknown => {
  const { steps } = input as Input;
  const results = steps.map((step) => ({ premium: quotePremium(step) }));
  return { results };
};

