  it.todo("loyalty discount (>=2 years) applies 20% off the policy base premium");
  it.todo("exactly 2 years customer receives loyalty discount");
  it.todo("follow-up contract (second quote in scenario) applies 15% discount");
  it.todo("first-insurance surcharge applies per item even for follow-up contracts");

  // Multi-item modifier scope
  it.todo("cursed surcharge applies only to cursed item, not whole policy");

  // Rounding
  it.todo("premium rounds up in MHPCO's favor");

