  it.todo("newcomer with cursed sword: 165 G");
  it.todo("long-standing customer's second contract with cursed enchantment-7 sword: 160 G");

  // Claim: basic payouts
  it.todo("regular sword damage 500 G yields payout 400 G (minus 100 deductible)");
  it.todo("damage to rune (250 G value) of 200 G yields payout 100 G");
  it.todo("high-enchantment (>=8) item: 50% reimbursement then deductible");
  it.todo("dragon material item: full reimbursement then deductible");
  it.todo("dragon material with enchantment 9: 50% wins, then deductible");

  // Claim: cap and deductible
  it.todo("payout capped at 2x insurance sum across multiple claims");
  it.todo("deductible applies per damaged item entry");
  it.todo("two-sword policy: insurance sum 2000, cap 4000");
  it.todo("payout rounds down in MHPCO's favor");

  // Errors
  it.todo("quote with unknown item type causes non-zero exit");
  it.todo("claim against item not in policy causes non-zero exit");
  it.todo("claim with negative damage amount causes non-zero exit");
  it.todo("more damages of a type than insured items causes non-zero exit");

  // CLI
