const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
};

type Item = { type: string };
type Step = { op: string; items: Item[] };
type Input = { steps: Step[] };

const COMPONENT_TYPES = new Set(["rune"]);
const BLOCK_BASE_PREMIUM = 60;
const BLOCK_SIZE = 3;

const withFirstInsurance = (base: number): number =>
  base + base * FIRST_INSURANCE_SURCHARGE_RATE;

const itemBasePremium = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;

const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);

const groupByType = (items: Item[]): Map<string, Item[]> => {
  const groups = new Map<string, Item[]>();
  for (const item of items) {
    const group = groups.get(item.type) ?? [];
    group.push(item);
    groups.set(item.type, group);
  }
  return groups;
};

const componentGroupBasePremium = (group: Item[]): number =>
  group.length === BLOCK_SIZE
    ? BLOCK_BASE_PREMIUM
    : group.reduce((sum, item) => sum + itemBasePremium(item), 0);

const sum = (values: number[]): number => values.reduce((a, b) => a + b, 0);

const itemsSubtotal = (items: Item[]): number => {
  const components = items.filter(isComponent);
  const nonComponents = items.filter((item) => !isComponent(item));

  const nonComponentPremiums = nonComponents.map((item) =>
    withFirstInsurance(itemBasePremium(item)),
  );
  const componentGroupPremiums = [...groupByType(components).values()].map(
    (group) => withFirstInsurance(componentGroupBasePremium(group)),
  );

  return sum(nonComponentPremiums) + sum(componentGroupPremiums);
};

const quotePremium = (step: Step): number => {
  return Math.ceil(itemsSubtotal(step.items)) + PROCESSING_FEE;
};

export const runScenario = (input: unknown): unknown => {
  const { steps } = input as Input;
  const results = steps.map((step) => ({ premium: quotePremium(step) }));
  return { results };
};

